import{_ as a,o as t,c as i,ak as n}from"./chunks/framework.DkeEmzcj.js";const h=JSON.parse('{"title":"Privacy Policy - Punjab Educare","description":"","frontmatter":{"title":"Privacy Policy - Punjab Educare"},"headers":[],"relativePath":"punjab-educare/privacy-policy.md","filePath":"punjab-educare/privacy-policy.md","lastUpdated":1772239947000}'),r={name:"punjab-educare/privacy-policy.md"};function o(s,e,c,l,d,u){return t(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to “Privacy Policy”">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Important notice</p><p>Students do <strong>not</strong> create accounts in Punjab Educare. This policy applies to <strong>teachers and administrators</strong> who register and maintain accounts for content management and internal operations.</p></div><h2 id="who-we-are" tabindex="-1">Who we are <a class="header-anchor" href="#who-we-are" aria-label="Permalink to “Who we are”">​</a></h2><ul><li><strong>Product:</strong> Punjab Educare App</li><li><strong>Controller/Developer:</strong> BXAMRA</li><li><strong>Contact:</strong> <a href="mailto:bxamra@icloud.com" target="_blank" rel="noreferrer">bxamra@icloud.com</a>, <a href="mailto:support@punjabeducare.co.in" target="_blank" rel="noreferrer">support@punjabeducare.co.in</a></li><li><strong>Grievance Officer (India DPDP 2023):</strong> Jasamrit Singh Bhamra — <a href="mailto:bxamra@icloud.com" target="_blank" rel="noreferrer">bxamra@icloud.com</a></li></ul><h2 id="policy-coverage" tabindex="-1">Policy coverage <a class="header-anchor" href="#policy-coverage" aria-label="Permalink to “Policy coverage”">​</a></h2><p>This policy covers all Punjab Educare apps, as they share the same backend API.</p><p><code>Android</code> <code>iOS (when Available)</code><br><code>Teacher Desktop</code> <code>Admin Desktop</code><br><code>PWA / Web App (in Development)</code></p><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to “Scope”">​</a></h2><p>This policy covers data handled by the Punjab Educare apps, backend APIs, and supporting services used for teacher authentication, question submissions, content management, and administrative functions. It applies to registered teachers and administrators only.</p><h2 id="data-we-collect" tabindex="-1">Data we collect <a class="header-anchor" href="#data-we-collect" aria-label="Permalink to “Data we collect”">​</a></h2><p>Data collected from registered teachers and administrators may include:</p><ul><li><strong>Account and profile:</strong> Name, email/phone, teaching subjects, school/institution affiliation, role (teacher/admin), language preferences</li><li><strong>Authentication:</strong> Hashed credentials, tokens, one-time codes, session identifiers</li><li><strong>App activity:</strong> Submitted content, approval workflows, progress tracking, timestamps</li><li><strong>Question submissions:</strong> Educational content (questions, answers, explanations, metadata) submitted by teachers for academic purposes</li><li><strong>Device and diagnostics:</strong> App version, device/OS information, crash logs, performance metrics, coarse network information</li><li><strong>Communications:</strong> Support messages, feedback, error reports, attachments you provide</li><li><strong>Optional permissions (depending on platform):</strong> Camera (verification/content), photos/files (upload/download), notifications (service updates)</li></ul><h2 id="how-we-use-data" tabindex="-1">How we use data <a class="header-anchor" href="#how-we-use-data" aria-label="Permalink to “How we use data”">​</a></h2><ul><li>Provide and improve core features (question submissions, content management, approvals)</li><li>Authenticate users, enforce role-based permissions, and secure accounts</li><li>Process and review educational content submitted for inclusion in the platform</li><li>Monitor reliability, diagnose issues, and prevent fraud/abuse</li><li>Send essential service messages (submission status updates, password resets) and administrative notifications</li></ul><h2 id="question-submissions-and-intellectual-property" tabindex="-1">Question submissions and intellectual property <a class="header-anchor" href="#question-submissions-and-intellectual-property" aria-label="Permalink to “Question submissions and intellectual property”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Important</p><p>Please read this section carefully if you plan to submit educational content.</p></div><ul><li><strong>Teacher submissions:</strong> Educational content submitted by teachers is reviewed before being added to the main question bank.</li><li><strong>Permanent retention:</strong> Accepted educational content is permanently retained and cannot be requested for removal.</li><li><strong>Academic integrity:</strong> Submitted content may be used for educational purposes, curriculum development, and assessment creation.</li><li><strong>Related notice:</strong> For intellectual property, licensing, and collaboration terms, see: <strong><a href="/products/punjab-educare/intellectual-property-collaboration-notice">Intellectual Property &amp; Collaboration Notice</a></strong></li></ul><h2 id="data-sharing" tabindex="-1">Data sharing <a class="header-anchor" href="#data-sharing" aria-label="Permalink to “Data sharing”">​</a></h2><p>Data is not sold. Limited sharing may occur with:</p><ul><li>Service providers (processors) for hosting, storage, crash reporting, analytics, notifications, and security scanning (under data protection agreements)</li><li>Punjab Department of Education and authorized educational authorities for curriculum oversight and quality assurance</li><li>Legal and safety reasons (to comply with law, defend legal claims, or prevent harm/abuse)</li></ul><h2 id="retention" tabindex="-1">Retention <a class="header-anchor" href="#retention" aria-label="Permalink to “Retention”">​</a></h2><ul><li><strong>Teacher account data:</strong> Retained while the account is active; deleted within <strong>4 weeks</strong> after a confirmed deletion request unless retention is required by law</li><li><strong>Submitted educational content:</strong> Permanently retained once accepted</li><li><strong>Submission records:</strong> Maintained for academic integrity/audit as required by educational authorities</li><li><strong>Logs and diagnostics:</strong> Typically 30–180 days unless needed longer for security investigations</li></ul><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to “Security”">​</a></h2><ul><li>Encryption in transit (TLS) and at rest for sensitive data</li><li>Credential hashing (bcrypt/Argon2) and scoped access tokens</li><li>Role-based access control for teachers and administrators</li><li>Monitoring, rate limiting, and safeguards against unauthorized access</li></ul><h2 id="account-and-data-deletion" tabindex="-1">Account and data deletion <a class="header-anchor" href="#account-and-data-deletion" aria-label="Permalink to “Account and data deletion”">​</a></h2><p>For teacher accounts:</p><ul><li>Send a deletion request to <strong><a href="mailto:accounts@punjabeducare.co.in" target="_blank" rel="noreferrer">accounts@punjabeducare.co.in</a></strong> from the same email address used to register</li><li>Requests are processed within <strong>4 weeks</strong> of receiving a verified request</li><li>Your account will be deleted, but accepted/approved educational content you contributed remains permanently (typically de-identified)</li></ul><p>For step-by-step instructions, see: <strong><a href="/products/punjab-educare/delete-account">Account Deletion Request</a></strong></p><h2 id="changes-to-this-policy" tabindex="-1">Changes to This Policy <a class="header-anchor" href="#changes-to-this-policy" aria-label="Permalink to “Changes to This Policy”">​</a></h2><p>We may update our Privacy Policy from time to time. We will notify you of any changes by posting the new Privacy Policy on this page. You are advised to review this Privacy Policy periodically for any changes. Changes to this Privacy Policy are effective when they are posted on this page.</p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to “Contact”">​</a></h2><ul><li><strong>Privacy inquiries:</strong> <a href="mailto:accounts@punjabeducare.co.in" target="_blank" rel="noreferrer">accounts@punjabeducare.co.in</a></li><li><strong>Support:</strong> <a href="mailto:support@punjabeducare.co.in" target="_blank" rel="noreferrer">support@punjabeducare.co.in</a></li></ul><p><strong>Grievance Officer (India DPDP 2023):</strong><br> Jasamrit Singh Bhamra — <a href="mailto:bxamra@icloud.com" target="_blank" rel="noreferrer">bxamra@icloud.com</a></p>',33)])])}const m=a(r,[["render",o]]);export{h as __pageData,m as default};
